  if (state === true) {
    const yes = confirm('You have unsaved changes. Save before leaving?');
    if (yes) {
      const cur = variables[VAR_ID] ?? {};
      const next = { ...cur, isEditing: null };

      // Update the WeWeb variable (try common setters, then fallback)
      if (typeof utilsFunctions?.setVariableValue === 'function') {
        utilsFunctions.setVariableValue(VAR_ID, next);
      } else if (window.wwLib?.wwVariable?.updateValue) {
        window.wwLib.wwVariable.updateValue(VAR_ID, next);
      } else if (window.wwLib?.wwVariable?.setValue) {
        window.wwLib.wwVariable.setValue(VAR_ID, next);
      } else {
        try { variables[VAR_ID] = next; } catch (e) { }
      }
    }
    // In both cases (yes or no), go back
    utilsFunctions.goToPreviousPage('campaigns');
    return;
  }

  // state is null/undefined/false/'save' -> allow leaving without prompt
  utilsFunctions.goToPreviousPage('campaigns');
})();

